func (rt *RequestTracker) TrackRequest(ctx context.Context, userID, endpoint, method string, statusCode int, duration time.Duration, err error) {
	// Validate inputs
	if userID == "" || endpoint == "" || method == "" {
		return
	}

	// Increment request counter
	requestCounter.WithLabelValues(userID, endpoint, method, fmt.Sprintf("%d", statusCode)).Inc()

	// Observe duration
	requestDuration.WithLabelValues(userID, endpoint, method).Observe(duration.Seconds())

	// Handle error tracking
	if err != nil {
		errorCounter.WithLabelValues(userID, endpoint, "generic_error").Inc()
	}

	// Context cancellation tracking
	select {
	case <-ctx.Done():
		errorCounter.WithLabelValues(userID, endpoint, "context_cancelled").Inc()
	default:
	}
}

